"""ActPhase — 도구 실행, 이름 교정, 승인."""

from __future__ import annotations

import json
import logging

from mantis.executor.protocol import ExecutionContext
from mantis.executor.phases.protocol import PhaseResult

logger = logging.getLogger(__name__)


class DefaultAct:
    """기본 ActPhase.

    1. assistant 메시지 기록
    2. 도구 이름 교정 (search Provider 있으면 자동)
    3. on_before_tool 미들웨어 (승인 등)
    4. 도구 실행
    5. on_after_tool 미들웨어
    """

    name = "act"

    async def run(self, ctx: ExecutionContext) -> PhaseResult:
        response = ctx.pending_events  # will be set by pipeline
        # response is passed via ctx data from pipeline
        return PhaseResult(status="continue")

    async def execute(self, ctx: ExecutionContext, response: object) -> PhaseResult:
        """도구 호출 실행. response는 ModelResponse."""
        # assistant 메시지 기록 (tool_calls 포함)
        ctx.conversation.add_assistant(
            content=response.text,
            tool_calls=[
                {
                    "id": tc.id,
                    "type": "function",
                    "function": {
                        "name": tc.name,
                        "arguments": json.dumps(tc.arguments),
                    },
                }
                for tc in response.tool_calls
            ],
        )

        events = []

        for tc in response.tool_calls:
            name, args, block_reason = tc.name, tc.arguments, None

            # 도구 이름 교정 (search Provider 있으면)
            if ctx.search is not None:
                try:
                    corrected = ctx.search.correct(name)
                    if corrected and corrected != name:
                        logger.info("도구 이름 교정: '%s' → '%s'", name, corrected)
                        name = corrected
                except Exception:
                    pass

            # on_before_tool 미들웨어
            for mw in ctx.middlewares:
                name, args, block_reason = await mw.on_before_tool(
                    ctx.run_ctx, name, args,
                )
                if block_reason:
                    break

            if block_reason:
                ctx.conversation.add_tool_result(
                    tc.id,
                    tc.name,
                    json.dumps(
                        {"blocked": True, "reason": block_reason},
                        ensure_ascii=False,
                    ),
                )
                ctx.pending_events.append({
                    "type": "blocked",
                    "data": {"tool": tc.name, "reason": block_reason},
                })
                continue

            ctx.pending_events.append({
                "type": "tool_call",
                "data": {"name": name, "arguments": args},
            })

            # 도구 실행
            try:
                result = await ctx.registry.execute(
                    {"name": name, "arguments": args},
                    session_id=ctx.session_id,
                )
            except Exception as e:
                logger.error("도구 '%s' 실행 실패: %s", name, e)
                result = {"name": name, "error": str(e)}

            # on_after_tool 미들웨어
            for mw in ctx.middlewares:
                await mw.on_after_tool(ctx.run_ctx, name, args, result)

            # 결과 기록
            result_str = json.dumps(
                result.get("result", result.get("error", "")),
                ensure_ascii=False,
                default=str,
            )
            ctx.conversation.add_tool_result(tc.id, tc.name, result_str)

            ctx.pending_events.append({"type": "tool_result", "data": result})

        return PhaseResult(status="continue")
